func (s *Store) Status() (map[string]int, error) {
	rows, err := s.db.Query(
		`SELECT resource_type, COUNT(*) FROM resources GROUP BY resource_type ORDER BY resource_type`,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	status := make(map[string]int)
	for rows.Next() {
		var rt string
		var count int
		if err := rows.Scan(&rt, &count); err != nil {
			return nil, err
		}
		status[rt] = count
	}
	return status, rows.Err()
}

// ResolveByName resolves a human-readable name to a UUID from synced data.
// If the input is already a UUID, it is returned as-is.
// matchFields are JSON field names to search against (e.g., "name", "key", "email").
func (s *Store) ResolveByName(resourceType string, input string, matchFields ...string) (string, error) {
	if IsUUID(input) {
		return input, nil
	}

	var matches []string
	for _, field := range matchFields {
		query := fmt.Sprintf(
			`SELECT id FROM resources WHERE resource_type = ? AND LOWER(json_extract(data, '$.%s')) = LOWER(?)`,
			field,
		)
		rows, err := s.db.Query(query, resourceType, input)
		if err != nil {
			continue
		}
		for rows.Next() {
			var id string
			if rows.Scan(&id) == nil {
				// Deduplicate
				found := false
				for _, m := range matches {
					if m == id {
						found = true
						break
					}
				}
				if !found {
					matches = append(matches, id)
				}
			}
		}
		rows.Close()
	}

	switch len(matches) {
	case 0:
		return "", fmt.Errorf("%s %q not found in local store. Run 'sync' first, or use the UUID directly", resourceType, input)
	case 1:
		return matches[0], nil
	default:
		hint := matches[0]
		if len(matches) > 5 {
			hint = strings.Join(matches[:5], ", ") + "..."
		} else {
			hint = strings.Join(matches, ", ")
		}
		return "", fmt.Errorf("ambiguous: %q matches %d %s entries (%s). Use the exact UUID instead", input, len(matches), resourceType, hint)
	}
}

func (s *Store) UpsertTeam(sport, league string, data json.RawMessage) error {
	obj := unwrapEnvelope(data, "team")
	id := firstString(obj, "id", "uid")
	name := firstString(obj, "name", "shortDisplayName", "displayName")
	if id == "" || name == "" {
		return fmt.Errorf("team payload missing id or name")
	}

	_, err := s.db.Exec(
		`INSERT INTO teams (id, sport, league, abbreviation, name, display_name, location, color, logo_url, data, synced_at)
		 VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, CURRENT_TIMESTAMP)
		 ON CONFLICT(id) DO UPDATE SET
		 sport = excluded.sport,
		 league = excluded.league,
		 abbreviation = excluded.abbreviation,
		 name = excluded.name,
		 display_name = excluded.display_name,
		 location = excluded.location,
		 color = excluded.color,
		 logo_url = excluded.logo_url,
		 data = excluded.data,
		 synced_at = CURRENT_TIMESTAMP`,
		id, sport, league,
		firstString(obj, "abbreviation", "team.abbreviation"),
		name,
		firstString(obj, "displayName", "shortDisplayName", "nickname"),
		firstString(obj, "location"),
		firstString(obj, "color", "alternateColor"),
		firstString(obj, "logos.0.href", "logo", "links.0.href"),
		string(data),
	)
	return err
}

