func (s *Store) UpsertStandings(sport, league, season string, data json.RawMessage) error {
	obj := unwrapEnvelope(data, "team", "entry", "standing")
	teamID := firstString(obj, "team.id")
	id := firstString(obj, "id")
	if id == "" {
		if teamID != "" {
			id = strings.Join([]string{sport, league, season, teamID}, ":")
		} else {
			id = strings.Join([]string{sport, league, season, extractObjectID(obj)}, ":")
		}
	}
	if id == "" {
		return fmt.Errorf("standings payload missing identifier")
	}

	_, err := s.db.Exec(
		`INSERT INTO standings (id, sport, league, team_id, season, data, synced_at)
		 VALUES (?, ?, ?, ?, ?, ?, CURRENT_TIMESTAMP)
		 ON CONFLICT(id) DO UPDATE SET
		 sport = excluded.sport,
		 league = excluded.league,
		 team_id = excluded.team_id,
		 season = excluded.season,
		 data = excluded.data,
		 synced_at = CURRENT_TIMESTAMP`,
		id, sport, league, teamID, season, string(data),
	)
	return err
}

