func (s *Store) SearchAthletes(query string, limit int) ([]json.RawMessage, error) {
	return s.searchExternalContentTable("athletes", "athletes_fts", toFTSQuery(query), limit)
}

func (s *Store) SearchTeams(query string, limit int) ([]json.RawMessage, error) {
	return s.searchExternalContentTable("teams", "teams_fts", toFTSQuery(query), limit)
}

func (s *Store) SearchNews(query string, limit int) ([]json.RawMessage, error) {
	return s.searchExternalContentTable("news", "news_fts", toFTSQuery(query), limit)
}

func (s *Store) ListTeams(sport, league string) ([]json.RawMessage, error) {
	rows, err := s.db.Query(
		`SELECT data FROM teams WHERE sport = ? AND league = ? ORDER BY name`,
		sport, league,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	return scanRawMessages(rows)
}

func (s *Store) ListEvents(sport, league, date string) ([]json.RawMessage, error) {
	var (
		rows *sql.Rows
		err  error
	)
	if strings.TrimSpace(date) == "" {
		rows, err = s.db.Query(
			`SELECT data FROM events WHERE sport = ? AND league = ? ORDER BY date DESC`,
			sport, league,
		)
	} else {
		rows, err = s.db.Query(
			`SELECT data FROM events
			 WHERE sport = ? AND league = ? AND (
			 	date = ?
			 	OR date LIKE ? || '%'
			 	OR replace(substr(date, 1, 10), '-', '') = ?
			 )
			 ORDER BY date DESC`,
			sport, league, date, date, date,
		)
	}
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	return scanRawMessages(rows)
}

func (s *Store) GetTeamByAbbreviation(sport, league, abbrev string) (json.RawMessage, error) {
	var data string
	err := s.db.QueryRow(
		`SELECT data FROM teams
		 WHERE sport = ? AND league = ? AND LOWER(abbreviation) = LOWER(?)
		 LIMIT 1`,
		sport, league, abbrev,
	).Scan(&data)
	if err == sql.ErrNoRows {
		return nil, nil
	}
	if err != nil {
		return nil, err
	}
	return json.RawMessage(data), nil
}

func (s *Store) searchExternalContentTable(table, ftsTable, query string, limit int) ([]json.RawMessage, error) {
	if limit <= 0 {
		limit = 20
	}
	rows, err := s.db.Query(
		fmt.Sprintf(`SELECT b.data FROM %s b JOIN %s f ON b.rowid = f.rowid WHERE %s MATCH ? ORDER BY rank LIMIT ?`, table, ftsTable, ftsTable),
		query, limit,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	return scanRawMessages(rows)
}

func scanRawMessages(rows *sql.Rows) ([]json.RawMessage, error) {
	var results []json.RawMessage
	for rows.Next() {
		var data string
		if err := rows.Scan(&data); err != nil {
			return nil, err
		}
		results = append(results, json.RawMessage(data))
	}
	return results, rows.Err()
}

func toFTSQuery(query string) string {
	clean := regexp.MustCompile(`[^\pL\pN]+`).ReplaceAllString(strings.TrimSpace(query), " ")
	tokens := strings.Fields(clean)
	if len(tokens) == 0 {
		return `""`
	}
	for i, token := range tokens {
		tokens[i] = token + "*"
	}
	return strings.Join(tokens, " AND ")
}

func unwrapEnvelope(data json.RawMessage, keys ...string) map[string]any {
	var obj map[string]any
	if err := json.Unmarshal(data, &obj); err != nil {
		return map[string]any{}
	}
	for _, key := range keys {
		if nested, ok := obj[key].(map[string]any); ok {
			return nested
		}
	}
	return obj
}

func firstString(obj map[string]any, paths ...string) string {
	for _, path := range paths {
		if v, ok := digValue(obj, path); ok {
			switch value := v.(type) {
			case string:
				if value != "" {
					return value
				}
			case json.Number:
				return value.String()
			case float64:
				return strconv.FormatInt(int64(value), 10)
			case int:
				return strconv.Itoa(value)
			case fmt.Stringer:
				return value.String()
			default:
				text := strings.TrimSpace(fmt.Sprintf("%v", value))
				if text != "" && text != "<nil>" {
					return text
				}
			}
		}
	}
	return ""
}

func digValue(obj map[string]any, path string) (any, bool) {
	var current any = obj
	for _, part := range strings.Split(path, ".") {
		switch typed := current.(type) {
		case map[string]any:
			value, ok := typed[part]
			if !ok {
				return nil, false
			}
			current = value
		case []any:
			idx, err := strconv.Atoi(part)
			if err != nil || idx < 0 || idx >= len(typed) {
				return nil, false
			}
			current = typed[idx]
		default:
			return nil, false
		}
	}
	return current, true
}

func extractCompetitors(obj map[string]any) (homeID, awayID string, homeScore, awayScore int) {
	competitions, ok := digValue(obj, "competitions.0.competitors")
	if !ok {
		competitions, ok = obj["competitors"]
	}
	items, ok := competitions.([]any)
	if !ok {
		return "", "", 0, 0
	}

	for _, item := range items {
		competitor, ok := item.(map[string]any)
		if !ok {
			continue
		}
		homeAway := firstString(competitor, "homeAway")
		teamID := firstString(competitor, "team.id", "id")
		score := atoi(firstString(competitor, "score"))
		if homeAway == "home" {
			homeID = teamID
			homeScore = score
			continue
		}
		if homeAway == "away" {
			awayID = teamID
			awayScore = score
		}
	}
	return homeID, awayID, homeScore, awayScore
}

func atoi(s string) int {
	n, _ := strconv.Atoi(strings.TrimSpace(s))
	return n
}
